221→// estimateRowCount estimates the number of Parquet rows a CheckpointFile will produce.
222→// Used for pre-allocating the rows slice to avoid repeated append doubling.
223→func estimateRowCount(cf *CheckpointFile) int {
224→	n := 0
225→	for _, cm := range cf.Metrics {
226→		n += len(cm.Data)
227→	}
228→	for _, child := range cf.Children {
229→		n += estimateRowCount(child)
230→	}
231→	return n
232→}
233→
234→// archiveCheckpointsToParquet reads checkpoint files for a host directory,
235→// converts them to Parquet rows. Returns the rows and filenames that were processed.
236→func archiveCheckpointsToParquet(dir, cluster, host string, from int64) ([]ParquetMetricRow, []string, error) {
237→	entries, err := os.ReadDir(dir)
238→	if err != nil {
239→		return nil, nil, err
240→	}
241→
242→	files, err := findFiles(entries, from, false)
243→	if err != nil {
244→		return nil, nil, err
245→	}
246→
247→	if len(files) == 0 {
248→		return nil, nil, nil
249→	}
250→
251→	// First pass: load checkpoints and estimate total rows for pre-allocation.
252→	type loaded struct {
253→		cf       *CheckpointFile
254→		filename string
255→	}
256→	var checkpoints []loaded
257→	totalEstimate := 0
258→
259→	for _, checkpoint := range files {
260→		filename := filepath.Join(dir, checkpoint)
261→		cf, err := loadCheckpointFileFromDisk(filename)
262→		if err != nil {
263→			cclog.Warnf("[METRICSTORE]> skipping unreadable checkpoint %s: %v", filename, err)
264→			continue
265→		}
266→		totalEstimate += estimateRowCount(cf)
267→		checkpoints = append(checkpoints, loaded{cf: cf, filename: checkpoint})
268→	}
269→
270→	if len(checkpoints) == 0 {
271→		return nil, nil, nil
272→	}
273→
274→	rows := make([]ParquetMetricRow, 0, totalEstimate)
275→	processedFiles := make([]string, 0, len(checkpoints))
276→
277→	for _, cp := range checkpoints {
278→		rows = flattenCheckpointFile(cp.cf, cluster, host, "node", "", rows)
279→		processedFiles = append(processedFiles, cp.filename)
280→	}
281→
282→	return rows, processedFiles, nil
283→}
