 24→// createParquetTarget creates a ParquetTarget (file or S3) from the retention config.
 25→func createParquetTarget(cfg Retention) (pqarchive.ParquetTarget, error) {
 26→	switch cfg.TargetKind {
 27→	case "s3":
 28→		return pqarchive.NewS3Target(pqarchive.S3TargetConfig{
 29→			Endpoint:     cfg.TargetEndpoint,
 30→			Bucket:       cfg.TargetBucket,
