169→// archiveCheckpoints archives checkpoint files to Parquet format.
170→// Produces one Parquet file per cluster: <cleanupDir>/<cluster>/<timestamp>.parquet
171→// Each host's rows are written as a separate row group to avoid accumulating
172→// all data in memory at once.
173→func archiveCheckpoints(checkpointsDir, cleanupDir string, from int64) (int, error) {
174→	clusterEntries, err := os.ReadDir(checkpointsDir)
175→	if err != nil {
176→		return 0, err
177→	}
178→
179→	totalFiles := 0
180→
181→	for _, clusterEntry := range clusterEntries {
182→		if !clusterEntry.IsDir() {
183→			continue
184→		}
185→
186→		cluster := clusterEntry.Name()
187→		hostEntries, err := os.ReadDir(filepath.Join(checkpointsDir, cluster))
188→		if err != nil {
189→			return totalFiles, err
190→		}
191→
192→		// Stream per-host rows to parquet writer via worker pool
193→		type hostResult struct {
194→			rows  []ParquetMetricRow
195→			files []string // checkpoint filenames to delete after successful write
196→			dir   string   // checkpoint directory for this host
197→		}
198→
199→		results := make(chan hostResult, len(hostEntries))
200→		work := make(chan struct {
201→			dir, host string
202→		}, Keys.NumWorkers)
203→
204→		var wg sync.WaitGroup
205→		errs := int32(0)
206→
207→		wg.Add(Keys.NumWorkers)
208→		for w := 0; w < Keys.NumWorkers; w++ {
209→			go func() {
210→				defer wg.Done()
211→				for item := range work {
212→					rows, files, err := archiveCheckpointsToParquet(item.dir, cluster, item.host, from)
213→					if err != nil {
214→						cclog.Errorf("[METRICSTORE]> error reading checkpoints for %s/%s: %s", cluster, item.host, err.Error())
215→						atomic.AddInt32(&errs, 1)
216→						continue
217→					}
218→					if len(rows) > 0 {
219→						results <- hostResult{rows: rows, files: files, dir: item.dir}
220→					}
221→				}
222→			}()
223→		}
224→
225→		go func() {
226→			for _, hostEntry := range hostEntries {
227→				if !hostEntry.IsDir() {
228→					continue
229→				}
230→				dir := filepath.Join(checkpointsDir, cluster, hostEntry.Name())
231→				work <- struct {
232→					dir, host string
233→				}{dir: dir, host: hostEntry.Name()}
234→			}
235→			close(work)
236→			wg.Wait()
237→			close(results)
238→		}()
239→
240→		// Open streaming writer and write each host's rows as a row group
241→		parquetFile := filepath.Join(cleanupDir, cluster, fmt.Sprintf("%d.parquet", from))
242→		writer, err := newParquetArchiveWriter(parquetFile)
243→		if err != nil {
244→			// Drain results channel to unblock workers
245→			for range results {
246→			}
247→			return totalFiles, fmt.Errorf("creating parquet writer for cluster %s: %w", cluster, err)
248→		}
249→
250→		type deleteItem struct {
251→			dir   string
252→			files []string
253→		}
254→		var toDelete []deleteItem
255→		writeErr := error(nil)
256→
257→		for r := range results {
258→			if writeErr == nil {
259→				sortParquetRows(r.rows)
260→				if err := writer.WriteHostRows(r.rows); err != nil {
261→					writeErr = err
262→				}
263→			}
264→			// Always track files for deletion (even if write failed, we still drain)
265→			toDelete = append(toDelete, deleteItem{dir: r.dir, files: r.files})
266→		}
267→
268→		if err := writer.Close(); err != nil && writeErr == nil {
269→			writeErr = err
270→		}
271→
272→		if errs > 0 {
273→			return totalFiles, fmt.Errorf("%d errors reading checkpoints for cluster %s", errs, cluster)
274→		}
275→
276→		if writer.count == 0 {
277→			// No data written — remove empty file
278→			os.Remove(parquetFile)
279→			continue
280→		}
281→
282→		if writeErr != nil {
283→			os.Remove(parquetFile)
284→			return totalFiles, fmt.Errorf("writing parquet archive for cluster %s: %w", cluster, writeErr)
285→		}
286→
287→		// Delete archived checkpoint files
288→		for _, item := range toDelete {
289→			for _, file := range item.files {
290→				filename := filepath.Join(item.dir, file)
291→				if err := os.Remove(filename); err != nil {
292→					cclog.Warnf("[METRICSTORE]> could not remove archived checkpoint %s: %v", filename, err)
293→				} else {
294→					totalFiles++
295→				}
296→			}
297→		}
298→
299→		cclog.Infof("[METRICSTORE]> archived %d rows from %d files for cluster %s to %s",
300→			writer.count, totalFiles, cluster, parquetFile)

