 78→func TestJobToParquetRowConversion(t *testing.T) {
 79→	meta, data := makeTestJob(1001)
 80→	meta.Tags = []*schema.Tag{{Type: "test", Name: "tag1"}}
 81→	meta.MetaData = map[string]string{"key": "value"}
 82→
 83→	row, err := JobToParquetRow(meta, data)
 84→	if err != nil {
 85→		t.Fatalf("JobToParquetRow: %v", err)
 86→	}
 87→
 88→	if row.JobID != 1001 {
 89→		t.Errorf("JobID = %d, want 1001", row.JobID)
 90→	}
 91→	if row.Cluster != "testcluster" {
 92→		t.Errorf("Cluster = %q, want %q", row.Cluster, "testcluster")
 93→	}
 94→	if row.User != "testuser" {
 95→		t.Errorf("User = %q, want %q", row.User, "testuser")
 96→	}
 97→	if row.State != "completed" {
 98→		t.Errorf("State = %q, want %q", row.State, "completed")
 99→	}
100→	if row.NumNodes != 2 {
101→		t.Errorf("NumNodes = %d, want 2", row.NumNodes)
102→	}
103→
104→	// Verify resources JSON
105→	var resources []*schema.Resource
106→	if err := json.Unmarshal(row.ResourcesJSON, &resources); err != nil {
107→		t.Fatalf("unmarshal resources: %v", err)
108→	}
109→	if len(resources) != 2 {
110→		t.Errorf("resources len = %d, want 2", len(resources))
111→	}
112→
113→	// Verify tags JSON
114→	var tags []*schema.Tag
115→	if err := json.Unmarshal(row.TagsJSON, &tags); err != nil {
116→		t.Fatalf("unmarshal tags: %v", err)
117→	}
118→	if len(tags) != 1 || tags[0].Name != "tag1" {
119→		t.Errorf("tags = %v, want [{test tag1}]", tags)
120→	}
121→
122→	// Verify metric data is gzip-compressed valid JSON
123→	gz, err := gzip.NewReader(bytes.NewReader(row.MetricDataGz))
124→	if err != nil {
125→		t.Fatalf("gzip reader: %v", err)
126→	}
127→	decompressed, err := io.ReadAll(gz)
128→	if err != nil {
129→		t.Fatalf("gzip read: %v", err)
130→	}
131→	var jobData schema.JobData
132→	if err := json.Unmarshal(decompressed, &jobData); err != nil {
133→		t.Fatalf("unmarshal metric data: %v", err)
134→	}
135→	if _, ok := jobData["cpu_load"]; !ok {
136→		t.Error("metric data missing cpu_load key")
137→	}
