 13→	"time"
 14→
 15→	cclog "github.com/ClusterCockpit/cc-lib/v2/ccLogger"
 16→	"github.com/ClusterCockpit/cc-lib/v2/schema"
 17→	pq "github.com/parquet-go/parquet-go"
 18→)
 19→
 20→// ParquetWriter batches ParquetJobRows and flushes them to a target
 21→// when the estimated size exceeds maxSizeBytes.
 22→type ParquetWriter struct {
 23→	target       ParquetTarget
 24→	maxSizeBytes int64
 25→	rows         []ParquetJobRow
 26→	currentSize  int64
 27→	fileCounter  int
 28→	datePrefix   string
 29→}
 30→
 31→// NewParquetWriter creates a new writer that flushes batches to the given target.
 32→// maxSizeMB sets the approximate maximum size per parquet file in megabytes.
 33→func NewParquetWriter(target ParquetTarget, maxSizeMB int) *ParquetWriter {
 34→	return &ParquetWriter{
 35→		target:       target,
 36→		maxSizeBytes: int64(maxSizeMB) * 1024 * 1024,
 37→		datePrefix:   time.Now().Format("2006-01-02"),
 38→	}
 39→}
 40→
 41→// AddJob adds a row to the current batch. If the estimated batch size
 42→// exceeds the configured maximum, the batch is flushed to the target first.
 43→func (pw *ParquetWriter) AddJob(row ParquetJobRow) error {
 44→	rowSize := estimateRowSize(&row)
 45→
 46→	if pw.currentSize+rowSize > pw.maxSizeBytes && len(pw.rows) > 0 {
 47→		if err := pw.Flush(); err != nil {
 48→			return err
 49→		}
 50→	}
 51→
 52→	pw.rows = append(pw.rows, row)
 53→	pw.currentSize += rowSize
 54→	return nil
 55→}
 56→
 57→// Flush writes the current batch to a parquet file on the target.
 58→func (pw *ParquetWriter) Flush() error {
 59→	if len(pw.rows) == 0 {
 60→		return nil
 61→	}
 62→
 63→	pw.fileCounter++
 64→	fileName := fmt.Sprintf("cc-archive-%s-%03d.parquet", pw.datePrefix, pw.fileCounter)
 65→
 66→	data, err := writeParquetBytes(pw.rows)
 67→	if err != nil {
 68→		return fmt.Errorf("write parquet buffer: %w", err)
 69→	}
 70→
 71→	if err := pw.target.WriteFile(fileName, data); err != nil {
 72→		return fmt.Errorf("write parquet file %q: %w", fileName, err)
 73→	}
 74→
 75→	cclog.Infof("Parquet retention: wrote %s (%d jobs, %d bytes)", fileName, len(pw.rows), len(data))
 76→	pw.rows = pw.rows[:0]
 77→	pw.currentSize = 0
 78→	return nil
 79→}
 80→
 81→// Close flushes any remaining rows and finalizes the writer.
 82→func (pw *ParquetWriter) Close() error {
 83→	return pw.Flush()
 84→}
 85→
 86→func writeParquetBytes(rows []ParquetJobRow) ([]byte, error) {
 87→	var buf bytes.Buffer
 88→
 89→	writer := pq.NewGenericWriter[ParquetJobRow](&buf,
 90→		pq.Compression(&pq.Zstd),
 91→		pq.SortingWriterConfig(pq.SortingColumns(
 92→			pq.Ascending("sub_cluster"),
 93→			pq.Ascending("project"),
 94→			pq.Ascending("start_time"),
 95→		)),
 96→	)
 97→
 98→	if _, err := writer.Write(rows); err != nil {
 99→		return nil, err
100→	}
101→	if err := writer.Close(); err != nil {
102→		return nil, err
103→	}
104→
105→	return buf.Bytes(), nil
106→}
107→
108→func estimateRowSize(row *ParquetJobRow) int64 {
109→	// Fixed fields: ~100 bytes for numeric fields + strings estimate
110→	size := int64(200)
111→	size += int64(len(row.Cluster) + len(row.SubCluster) + len(row.Partition) +
112→		len(row.Project) + len(row.User) + len(row.State))
113→	size += int64(len(row.ResourcesJSON))
114→	size += int64(len(row.StatisticsJSON))
115→	size += int64(len(row.TagsJSON))
116→	size += int64(len(row.MetaDataJSON))
117→	size += int64(len(row.FootprintJSON))
118→	size += int64(len(row.EnergyFootJSON))
119→	size += int64(len(row.MetricDataGz))
120→	return size
121→}
122→
123→// prefixedTarget wraps a ParquetTarget and prepends a path prefix to all file names.
124→type prefixedTarget struct {
125→	inner  ParquetTarget
126→	prefix string
127→}
128→
129→func (pt *prefixedTarget) WriteFile(name string, data []byte) error {
130→	return pt.inner.WriteFile(path.Join(pt.prefix, name), data)
131→}
132→
133→// ClusterAwareParquetWriter organizes Parquet output by cluster.
134→// Each cluster gets its own subdirectory with a cluster.json config file.
135→type ClusterAwareParquetWriter struct {
136→	target       ParquetTarget
137→	maxSizeMB    int
138→	writers      map[string]*ParquetWriter
139→	clusterCfgs  map[string]*schema.Cluster
140→}
141→
142→// NewClusterAwareParquetWriter creates a writer that routes jobs to per-cluster ParquetWriters.
143→func NewClusterAwareParquetWriter(target ParquetTarget, maxSizeMB int) *ClusterAwareParquetWriter {
144→	return &ClusterAwareParquetWriter{
145→		target:      target,
146→		maxSizeMB:   maxSizeMB,
147→		writers:     make(map[string]*ParquetWriter),
148→		clusterCfgs: make(map[string]*schema.Cluster),
149→	}
150→}
151→
152→// SetClusterConfig stores a cluster configuration to be written as cluster.json on Close.
153→func (cw *ClusterAwareParquetWriter) SetClusterConfig(name string, cfg *schema.Cluster) {
154→	cw.clusterCfgs[name] = cfg
155→}
156→
157→// AddJob routes the job row to the appropriate per-cluster writer.
158→func (cw *ClusterAwareParquetWriter) AddJob(row ParquetJobRow) error {
159→	cluster := row.Cluster
160→	pw, ok := cw.writers[cluster]
161→	if !ok {
162→		pw = NewParquetWriter(&prefixedTarget{inner: cw.target, prefix: cluster}, cw.maxSizeMB)
163→		cw.writers[cluster] = pw
164→	}
165→	return pw.AddJob(row)
166→}
167→
168→// Close writes cluster.json files and flushes all per-cluster writers.
169→func (cw *ClusterAwareParquetWriter) Close() error {
170→	for name, cfg := range cw.clusterCfgs {
171→		data, err := json.MarshalIndent(cfg, "", "  ")
172→		if err != nil {
173→			return fmt.Errorf("marshal cluster config %q: %w", name, err)
174→		}
175→		if err := cw.target.WriteFile(path.Join(name, "cluster.json"), data); err != nil {
176→			return fmt.Errorf("write cluster.json for %q: %w", name, err)
177→		}
178→	}
179→
180→	for cluster, pw := range cw.writers {
181→		if err := pw.Close(); err != nil {
182→			return fmt.Errorf("close writer for cluster %q: %w", cluster, err)
183→		}
184→	}
185→	return nil
186→}
